    tags: ['情绪认知', '武志红', '身体知道答案', '身心分离', '躯体化'],
    keywords: ['武志红', '身体知道答案', '身体', '胃疼', '头痛', '失眠', '肩膀紧', '身心分离', '躯体化', '情绪压抑', '身体信号', '听身体', '身体说话', '说不出口', '委屈', '为什么家会伤人', '中国心理学家', '直觉', '身体感受', '疑神疑鬼'],
