    keywords: ['李松蔚', '5%的改变', '微小改变', '死循环', '改变', '惯性', '打破', '拖延', '自我批评', '系统式', '一小步', '试试', '做不到', '改不了', '困住', '选项', '突破', '习惯', '重新开始', '放弃'],
