    tags: ['压力管理', '坚毅', '达克沃斯', '抗压', '坚持'],
    keywords: ['达克沃斯', '坚毅', 'Grit', '坚持', '死扛', '放弃', '天赋', '成功', '长期目标', '热情', '目标', '顶层目标', '为什么', '当初', '使命感', '刻意练习', '三分钟热度', '咬牙', '撑', '扛不住'],
