    tags: ['自我效能感', '班杜拉', '自信'],
    keywords: ['自我效能感', '班杜拉', '自信', '不敢做', '害怕失败', '不敢尝试', '自我怀疑', '社交恐惧', '拖延', '畏难', '逃避', '不自信', '胆怯', '害怕评价', '犹豫不决', '退缩', '怕出丑'],
