    keywords: ['失眠', '睡不着', '入睡困难', '熬夜', '睡眠不好', '半夜醒', '早醒', '多梦', '睡不踏实', '躺床上睡不着', '失眠焦虑', 'CBT-I', '认知行为疗法', '数羊'],
