    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20person%20standing%20calmly%20as%20colorful%20emotional%20waves%20flow%20around%20them%20without%20overwhelming,%20watercolor%20style,%20warm%20sage%20green%20and%20amber%20tones,%20calm%20and%20resilient%20atmosphere&image_size=landscape_4_3',
