    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20soft%20illustration%20of%20a%20mask%20being%20gently%20removed%20from%20a%20face,%20revealing%20warm%20light%20underneath,%20symbolizing%20finding%20true%20self,%20warm%20and%20tender%20mood&image_size=landscape_4_3',
