    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=open%20broken%20heart%20with%20light%20coming%20through%20symbolizing%20accepting%20vulnerability%20warm%20compassionate%20atmosphere',
