    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20warm%20minimalist%20illustration%20of%20a%20person%20sitting%20calmly%20while%20a%20gentle%20therapist%20figure%20helps%20them%20observe%20their%20own%20thoughts%20like%20floating%20clouds,%20soft%20pastel%20colors,%20healing%20atmosphere&image_size=landscape_4_3',
    keyConcept: {
      term: 'Clark & Wells认知模型 (Cognitive Model of Social Phobia, 1995)',
      explanation: 'David Clark和Adrian Wells提出社交焦虑的核心是"以自我为中心的信息加工"：进入社交场合时，注意力自动从外部转向内部，用"自己感受到的自己"替代"别人看到的自己"，并伴随安全行为和预期/事后加工，形成恶性循环。该模型为社交焦虑CBT治疗奠定了理论基础。',
    },
