    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20minimalist%20illustration%20of%20a%20person%20rising%20from%20a%20broken%20path%2C%20phoenix-like%20but%20understated%2C%20warm%20earth%20tones%20with%20a%20soft%20golden%20glow%2C%20flat%20vector%20style&image_size=landscape_4_3',
