    tags: ['失眠', '接纳', '森田疗法', 'ACT', '悖论干预'],
    keywords: ['失眠', '接纳', '和解', '森田疗法', 'ACT', '接纳承诺疗法', '顺其自然', '为所当为', '睡不着', '焦虑', '悖论干预', '放弃控制', '醒着', '怕失眠', '恐惧失眠'],
