    coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20family%20tree%20with%20roots%20connecting%20to%20a%20couple%20silhouette%2C%20simple%20illustration%2C%20warm%20earthy%20tones&image_size=landscape_4_3',
