  coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20gentle%20illustration%20of%20a%20small%20person%20riding%20on%20a%20large%20elephant%20walking%20through%20a%20sunlit%20forest%20path,%20warm%20morning%20light,%20symbolizing%20the%20relationship%20between%20reason%20and%20emotion,%20watercolor%20style,%20soft%20earthy%20tones&image_size=landscape_4_3',
  keyConcept: {
    term: '象与骑象人 (Elephant and Rider)',
    explanation: 'Haidt的经典比喻：理性是骑象人，情绪是大象——你以为在控制方向，其实大象才是真正做决定的那一个。',
  },
  relatedIds: ['meaning-2', 'meaning-5'],
  createdAt: '2025-01-24',
