  coverImage: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=A%20warm%20Chinese%20ink%20painting%20style%20illustration%20of%20a%20person%20peacefully%20practicing%20calligraphy%20by%20a%20window,%20golden%20afternoon%20light,%20bamboo%20shadow%20on%20paper,%20sense%20of%20flow%20and%20inner%20peace,%20soft%20ink%20wash%20tones,%20contemplative%20Eastern%20aesthetic&image_size=landscape_4_3',
